Implement global keyboard navigation for the TUI.

**Global Shortcuts (always available):**
| Key | Action |
|-----|--------|
| q | Quit (with unsaved changes warning) |
| / | Go to search screen |
| Esc | Back/Cancel |
| ? | Show help overlay |

**Navigation Shortcuts:**
| Key | Action |
|-----|--------|
| j/↓ | Move down |
| k/↑ | Move up |
| Enter | Select/Confirm |
| Tab | Next field |
| Shift+Tab | Previous field |

**Screen-specific Shortcuts:**
- Document in each screen's ActionBar
- Override global shortcuts when appropriate (e.g., / in search input)

**Implementation:**
```tsx
const AppShell: React.FC = () => {
  const { exit } = useApp()
  const { navigate, state } = useAppState()

  useInput((input, key) => {
    // Global shortcuts
    if (input === 'q' && !state.isDirty) exit()
    if (input === '/' && state.currentScreen.name !== 'search') {
      navigate({ name: 'search' })
    }
    if (key.escape) navigate.goBack()
  }, { isActive: !modalOpen })
}
```

Create Effect runtime provider to integrate Effect services with React/Ink components.

**Implementation:**
```tsx
// src/cli/context/runtime-context.tsx
import { ManagedRuntime, Layer } from "effect"
import { createContext, useContext, useMemo, ReactNode } from "react"
import { MainLayer } from "@/services"

type RuntimeType = ManagedRuntime.ManagedRuntime<MainServices, never>

const RuntimeContext = createContext<RuntimeType | null>(null)

export const RuntimeProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const runtime = useMemo(() => ManagedRuntime.make(MainLayer), [])

  return (
    <RuntimeContext.Provider value={runtime}>
      {children}
    </RuntimeContext.Provider>
  )
}

export const useRuntime = () => {
  const runtime = useContext(RuntimeContext)
  if (!runtime) throw new Error("RuntimeProvider not found")
  return runtime
}
```

